habit_card.content:
.habit-card {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 10px;
    border-bottom: 1px solid #ccc;
}
.habit-card.completed {
    text-decoration: line-through;
}
.habit-card input[type="checkbox"] {
    margin-right: 10px;
}
.habit-card .habit-name {
    flex-grow: 1;
}

