when.content:
document.getElementById('add-button').addEventListener('click', () => {
    const habitName = prompt("Enter habit name:");
    if (habitName && isUniqueHabitName(habitName)) {
        habits.push({ name: habitName, completed: false, date: new Date() });
        renderHabitList();
    } else {
        alert("Habit name must be unique.");
    }
});

document.getElementById('habit-list').addEventListener('change', (event) => {
    if (event.target.type === 'checkbox') {
        const index = Array.from(event.target.parentNode.parentNode.children).indexOf(event.target.parentNode);
        habits[index].completed = event.target.checked;
        renderHabitList();
    }
});

